  <script type="module">
    let curTab = 'female';
    let curPage = 0;

    function esc(s) {
      if (s === null || s === undefined) return '';
      return $('<span>').text(String(s)).html();
    }

    function getData() {
      const all = getAllVariables();
      const stat = _.get(all, 'stat_data', {});
      if (curTab === 'female') return _.get(stat, 'Female', {});
      return _.get(stat, 'Male', {});
    }

    function pwrCls(v) {
      if (!v || v === 'Tạm chưa thức tỉnh') return 'v-pwr-off';
      return 'v-pwr';
    }

    function virCls(v) {
      if (v === 'Có') return 'v-vir-y';
      if (v === 'Không') return 'v-vir-n';
      return 'v-vir-u';
    }

    function mkRow(label, value, cls) {
      return '<div class="f-row">'
        + '<span class="f-lbl">' + esc(label) + '</span>'
        + '<span class="f-val ' + cls + '">' + esc(value || '\u2014') + '</span>'
        + '</div>';
    }

    function render() {
      var chars = getData();
      var keys = Object.keys(chars).reverse();
      var total = keys.length;

      if (total === 0) {
        $('#char-card').hide();
        $('#cyber-pgr').hide();
        $('#empty-msg').show();
        return;
      }

      $('#empty-msg').hide();
      $('#char-card').show();

      if (curPage >= total) curPage = total - 1;
      if (curPage < 0) curPage = 0;

      var name = keys[curPage];
      var d = chars[name];

      /* handle uninitialized */
      if (d === 'Chờ khởi tạo' || typeof d !== 'object' || d === null) {
        $('#char-name-hd').text(name);
        $('#card-body').html('<div class="empty-msg">ĐANG KHỞI TẠO...</div>');
        renderPager(total);
        return;
      }

      $('#char-name-hd').text(d['Name'] || name);

      var h = '';
      h += mkRow('Giới tính', d['Gender'], 'v-def');
      h += mkRow('Tuổi', d['Age'], 'v-def');
      h += mkRow('Ngoại hình', d['Appearance'], 'v-appear');
      h += mkRow('Tính cách', d['Personality'], 'v-person');
      h += mkRow('Thân phận', d['Identity'], 'v-ident');
      h += mkRow('Dị năng', d['Ability'], pwrCls(d['Ability']));
      h += mkRow('Tình trạng', d['RelationshipStatus'], 'v-love');

      if (curTab === 'female') {
        h += mkRow('Dáng người', d['BodyShape'], 'v-fig');
        h += mkRow('Trinh tiết', d['IsVirgin'], virCls(d['IsVirgin']));
      }

      /* tags */
      var tagObj = d['ModifiedTags'];
      if (!tagObj || typeof tagObj !== 'object') tagObj = {};
      var tagKeys = Object.keys(tagObj);

      h += '<div class="tags-sec">';
      h += '<div class="tags-ttl">[ Thẻ tùy chỉnh ]</div>';

      if (tagKeys.length === 0) {
        h += '<div class="tags-nil">TRỐNG</div>';
      } else {
        h += '<div class="tags-grid">';
        tagKeys.forEach(function(k) {
          h += '<div class="tag-chip">';
          h += '<span class="tag-k">' + esc(k) + '</span>';
          h += '<span class="tag-v">' + esc(tagObj[k]) + '</span>';
          h += '</div>';
        });
        h += '</div>';
      }
      h += '</div>';

      $('#card-body').html(h);
      renderPager(total);
    }

    function renderPager(total) {
      if (total <= 1) {
        $('#cyber-pgr').hide();
        return;
      }
      $('#cyber-pgr').show();
      $('#prev-btn').prop('disabled', curPage <= 0);
      $('#next-btn').prop('disabled', curPage >= total - 1);
      $('#pg-inf').text((curPage + 1) + ' / ' + total);
    }

    async function init() {
      await waitGlobalInitialized('Mvu');

      render();

      eventOn(Mvu.events.VARIABLE_UPDATE_ENDED, function() {
        render();
      });

      $('.cyber-tab').on('click', function() {
        var tab = $(this).data('tab');
        if (tab === curTab) return;
        curTab = tab;
        curPage = 0;

        $('.cyber-tab').removeClass('act-f act-m');
        if (tab === 'female') {
          $(this).addClass('act-f');
        } else {
          $(this).addClass('act-m');
        }

        render();
      });

      $('#prev-btn').on('click', function() {
        if (curPage > 0) {
          curPage--;
          render();
        }
      });

      $('#next-btn').on('click', function() {
        var chars = getData();
        var total = Object.keys(chars).length;
        if (curPage < total - 1) {
          curPage++;
          render();
        }
      });
    }

    $(errorCatched(init));
  </script>
