import { registerMvuSchema } from 'https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js';

export const Schema = z.object({
  Female: z.record(
    z.string().describe('Tên nhân vật'),
    z.object({
      Name: z.string().prefault(''),
      Gender: z.literal('Nữ').prefault('Nữ'),
      Age: z.number().prefault(''),
      Appearance: z.string().prefault(''),
      Personality: z.string().prefault(''),
      Identity: z.string().prefault(''),
      Ability: z.string().prefault('Tạm chưa thức tỉnh'),
      RelationshipStatus: z.string().prefault(''),
      BodyShape: z.string().prefault(''),
      IsVirgin: z.string().prefault(''),
      ModifiedTags: z.record(
        z.string().describe('Tên thẻ'),
        z.string().describe('Giá trị thẻ'),
      ).prefault({}),
    }).or(z.literal('Chờ khởi tạo')).prefault('Chờ khởi tạo'),
  ),

  Male: z.record(
    z.string().describe('Tên nhân vật'),
    z.object({
      Name: z.string().prefault(''),
      Gender: z.literal('Nam').prefault('Nam'),
      Age: z.number().prefault(''),
      Appearance: z.string().prefault(''),
      Personality: z.string().prefault(''),
      Identity: z.string().prefault(''),
      Ability: z.string().prefault('Tạm chưa thức tỉnh'),
      RelationshipStatus: z.string().prefault(''),
      ModifiedTags: z.record(
        z.string().describe('Tên thẻ'),
        z.string().describe('Giá trị thẻ'),
      ).prefault({}),
    }).or(z.literal('Chờ khởi tạo')).prefault('Chờ khởi tạo'),
  ),
});

$(() => {
  registerMvuSchema(Schema);
});
